import java.util.Scanner;

public class ConsoleInput {
  public static void main(String[] args) {
    Scanner scanner = new Scanner(System.in);
    System.out.print("Enter your name: ");
    String name = scanner.nextLine(); // Sətir oxumaq
    System.out.print("Enter your age: ");
    int age = scanner.nextInt(); // Tam ədəd oxumaq
    System.out.print("Enter your height: ");
    double height = scanner.nextDouble(); // Onluq ədəd oxumaq
    System.out.println("Name: " + name + ", Age: " + age + ", Height: " + height);
    scanner.close(); // Scanner-i bağlamaq
  }
}
// Çıxış (istifadəçi girişindən asılıdır):
// Enter your name: Alice
// Enter your age: 25
// Enter your height: 1.75
// Name: Alice, Age: 25, Height: 1.75

import java.io.PrintWriter;
import java.io.File;

public class FileOutput {
  public static void main(String[] args) {
    try {
      PrintWriter writer = new PrintWriter(new File("output.txt"));
      writer.println("Hello, File!");
      writer.println("This is a test.");
      writer.close(); // Faylı bağlamaq
      System.out.println("Data written to file.");
    } catch (Exception e) {
      System.out.println("Error: " + e.getMessage());
    }
  }
}
// Çıxış: Data written to file.
// (output.txt faylına "Hello, File!" və "This is a test." yazılır)

import java.io.BufferedReader;
import java.io.FileReader;

public class FileInput {
  public static void main(String[] args) {
    try {
      BufferedReader reader = new BufferedReader(new FileReader("output.txt"));
      String line;
      while ((line = reader.readLine()) != null) {
        System.out.println(line);
      }
      reader.close(); // Faylı bağlamaq
    } catch (Exception e) {
      System.out.println("Error: " + e.getMessage());
    }
  }
}
// Çıxış (əgər output.txt mövcuddursa):
// Hello, File!
// This is a test.

import java.util.Scanner;
import java.io.PrintWriter;
import java.io.File;

public class OrderSystem {
  public static void main(String[] args) {
    Scanner scanner = new Scanner(System.in);
    System.out.print("Enter product name: ");
    String productName = scanner.nextLine();
    System.out.print("Enter price: ");
    double price = scanner.nextDouble();

    try {
      PrintWriter writer = new PrintWriter(new File("order.txt"));
      writer.println("Product: " + productName);
      writer.println("Price: " + price);
      writer.close();
      System.out.println("Order saved to file.");

      BufferedReader reader = new BufferedReader(new FileReader("order.txt"));
      String line;
      System.out.println("Order details:");
      while ((line = reader.readLine()) != null) {
        System.out.println(line);
      }
      reader.close();
    } catch (Exception e) {
      System.out.println("Error: " + e.getMessage());
    }
    scanner.close();
  }
}
// Çıxış (istifadəçi girişindən asılıdır):
// Enter product name: Laptop
// Enter price: 999.99
// Order saved to file.
// Order details:
// Product: Laptop
// Price: 999.99

